In C++, you can start a new process and connect one file descriptor to its input and output using the `fork()` and `exec()` family of functions, along with file descriptor redirection. Here's a simple example:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/wait.h>
#include <stdio.h>

int main() {
    int pipefd[2];
    pid_t pid;

    // Create a pipe
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a child process
    pid = fork();
    if (pid < 0) {  // Error
        perror("fork");
        return 1;
    } else if (pid == 0) {  // Child process
        // Close the write end of the pipe
        close(pipefd[1]);

        // Redirection: file descriptor 0 (stdin) is now connected to the read end of the pipe
        dup2(pipefd[0], 0);

        // Close the pipe file descriptor
        close(pipefd[0]);

        // Execute the command, in this case, 'cat'
        execlp("cat", "cat", (char*)NULL);
        perror("execlp");
        _exit(1);  // Exit if execlp fails
    } else {  // Parent process
        // Close the read end of the pipe
        close(pipefd[0]);

        // Write to the pipe (simulating input to the child process)
        const char* input = "Hello from parent process\n";
        write(pipefd[1], input, strlen(input));

        // Close the write end of the pipe
        close(pipefd[1]);

        // Wait for the child process to finish
        wait(NULL);

        std::cout << "Parent process finished." << std::endl;
    }

    return 0;
}
```

In this example, we create a pipe and fork a child process. The child process reads from the pipe (which simulates input), and the parent process writes to the pipe (which serves as input for the child process). The `cat` command is used as a simple example to demonstrate the redirection.
